  1→import './login.css';
  2→import React, { useEffect, useState } from "react";
  3→import { useNavigate } from "react-router-dom";
  4→import { useAuth } from '../../Context/useAuth.js';
  5→import supabase from '../../utils/supabaseClient.js';
  6→
  7→const LoginPage = () => {
  8→    const [showPass, setShowPass] = useState(false);
  9→    const [password, setPassword] = useState('');
 10→    const [email, setEmail] = useState('');
 11→    const [errorMessage, setErrorMessage] = useState('');
 12→    const [successMessage, setSuccessMessage] = useState('');
 13→    const [isLoading, setIsLoading] = useState(false);
 14→    const [forgotMode, setForgotMode] = useState(false);
 15→
 16→    const { session } = useAuth();
 17→    const navigate = useNavigate();
 18→
 19→    const handleShowPass = (e) => {
 20→        e.preventDefault();
 21→        setShowPass((prev) => !prev);
 22→    };
 23→
 24→    const handleNavigate = (e) => {
 25→        e.preventDefault();
 26→        navigate('/signUp');
 27→    };
 28→
 29→    const handleLogin = async (e) => {
 30→        e.preventDefault();
 31→        setErrorMessage('');
 32→        setSuccessMessage('');
 33→        setIsLoading(true);
 34→        try {
 35→            const { error } = await supabase.auth.signInWithPassword({ email, password });
 36→            if (error) {
 37→                setIsLoading(false);
 38→                return setErrorMessage(error.message);
 39→            }
 40→            setSuccessMessage('Signed in. Redirecting...');
 41→            setTimeout(() => navigate('/home'), 600);
 42→        } catch (error) {
 43→            console.error('Error during sign-in:', error.message);
 44→            setErrorMessage(error.message);
 45→            setIsLoading(false);
 46→        }
 47→    };
 48→
 49→    const handleForgotPassword = async (e) => {
 50→        e.preventDefault();
 51→        setErrorMessage('');
 52→        setSuccessMessage('');
 53→        setIsLoading(true);
 54→        try {
 55→            const { error } = await supabase.auth.resetPasswordForEmail(email, {
 56→                redirectTo: window.location.origin + '/home/settings?recovery=true',
 57→            });
 58→            if (error) {
 59→                setIsLoading(false);
 60→                return setErrorMessage(error.message);
 61→            }
 62→            setSuccessMessage('Check your email for a password reset link.');
 63→        } catch (error) {
 64→            console.error('Error sending reset email:', error.message);
 65→            setErrorMessage(error.message);
 66→        } finally {
 67→            setIsLoading(false);
 68→        }
 69→    };
 70→
 71→    const toggleForgotMode = () => {
 72→        setForgotMode((prev) => !prev);
 73→        setErrorMessage('');
 74→        setSuccessMessage('');
 75→    };
 76→
 77→    useEffect(() => {
 78→        if (session) {
 79→            navigate('/home');
 80→        }
 81→    }, [session, navigate]);
 82→
 83→    const isSubmitDisabled = forgotMode ? !email || isLoading : !email || !password || isLoading;
 84→
 85→    return (
 86→        <div className='auth-shell login-shell'>
 87→            <section className='auth-panel'>
 88→                <div className='brand'>Iskrib</div>
 89→                <h1 className='panel-title'>A calm place to write, reflect, and share.</h1>
 90→                <p className='panel-copy'>
 91→                    Keep your thoughts in one quiet space. Publish when you are ready.
 92→                </p>
 93→                <div className='panel-details'>
 94→                    Minimalist editor · Private drafts · Thoughtful community
 95→                </div>
 96→            </section>
 97→
 98→            <section className='auth-form-panel'>
 99→                <div className='auth-form-card'>
100→                    <header>
101→                        <h2 className='form-title'>
102→                            {forgotMode ? 'Reset your password' : 'Welcome back'}
103→                        </h2>
104→                        <p className='form-subtitle'>
105→                            {forgotMode
106→                                ? "Enter your email and we'll send a reset link."
107→                                : 'Sign in to continue your writing journey.'}
108→                        </p>
109→                    </header>
110→
111→                    {forgotMode ? (
112→                        <form className='auth-form' onSubmit={handleForgotPassword} aria-busy={isLoading ? 'true' : 'false'}>
113→                            <div className='form-field'>
114→                                <label htmlFor='login-email'>Email</label>
115→                                <input
116→                                    id='login-email'
117→                                    type='email'
118→                                    autoComplete='email'
119→                                    value={email}
120→                                    onChange={(e) => setEmail(e.target.value)}
121→                                    placeholder='you@example.com'
122→                                    className='auth-input'
123→                                    required
124→                                />
125→                            </div>
126→
127→                            <button className='primary-button' type='submit' disabled={isSubmitDisabled}>
128→                                <span className='button-label'>Send Reset Link</span>
129→                                {isLoading && <span className='button-spinner' aria-hidden='true' />}
130→                            </button>
131→
132→                            <button
133→                                className='link-button'
134→                                type='button'
135→                                onClick={toggleForgotMode}
136→                            >
137→                                Back to login
138→                            </button>
139→                        </form>
140→                    ) : (
141→                        <form className='auth-form' onSubmit={handleLogin} aria-busy={isLoading ? 'true' : 'false'}>
142→                            <div className='form-field'>
143→                                <label htmlFor='login-email'>Email</label>
144→                                <input
145→                                    id='login-email'
146→                                    type='email'
147→                                    autoComplete='email'
148→                                    value={email}
149→                                    onChange={(e) => setEmail(e.target.value)}
150→                                    placeholder='you@example.com'
151→                                    className='auth-input'
152→                                    required
153→                                />
154→                            </div>
155→
156→                            <div className='form-field'>
157→                                <div className='forgot-password-row'>
158→                                    <label htmlFor='login-password'>Password</label>
159→                                    <button
160→                                        className='link-button'
161→                                        type='button'
162→                                        onClick={toggleForgotMode}
163→                                    >
164→                                        Forgot password?
165→                                    </button>
166→                                </div>
167→                                <div className='input-with-action'>
168→                                    <input
169→                                        id='login-password'
170→                                        type={showPass ? 'text' : 'password'}
171→                                        autoComplete='current-password'
172→                                        value={password}
173→                                        onChange={(e) => setPassword(e.target.value)}
174→                                        placeholder='Enter your password'
175→                                        className='auth-input'
176→                                        required
177→                                    />
178→                                    <button
179→                                        className='show-toggle'
180→                                        type='button'
181→                                        onClick={handleShowPass}
182→                                        aria-label={showPass ? 'Hide password' : 'Show password'}
183→                                    >
184→                                        {showPass ? 'Hide' : 'Show'}
185→                                    </button>
186→                                </div>
187→                            </div>
188→
189→                            <button className='primary-button' type='submit' disabled={isSubmitDisabled}>
190→                                <span className='button-label'>Log in</span>
191→                                {isLoading && <span className='button-spinner' aria-hidden='true' />}
192→                            </button>
193→
194→                            <button
195→                                className='secondary-button'
196→                                type='button'
197→                                onClick={() => navigate('/home')}
198→                                disabled={isLoading}
199→                            >
200→                                Explore Iskrib
201→                            </button>
202→                        </form>
203→                    )}
204→
205→                    <footer className='auth-footer'>
206→                        <span>Don&apos;t have an account?</span>
207→                        <button className='link-button' type='button' onClick={handleNavigate}>
208→                            Sign up
209→                        </button>
210→                    </footer>
211→
212→                    {errorMessage && (
213→                        <div className='form-message error' role='alert'>
214→                            {errorMessage}
215→                        </div>
216→                    )}
217→
218→                    {successMessage && (
219→                        <div className='form-message success' role='status'>
220→                            {successMessage}
221→                        </div>
222→                    )}
223→                </div>
224→            </section>
225→        </div>
226→    );
227→};
228→
229→export default LoginPage;
