  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import Loader from './components/loadingComponent/BgLoader.jsx';
  9→import SeoManager from './seo/SeoManager.jsx';
 10→
 11→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 12→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 13→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 14→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 15→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 16→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 17→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 18→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 19→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
 20→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 21→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 22→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 23→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 24→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 25→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 26→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 27→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 28→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 29→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 30→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 31→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 32→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 33→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 34→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 35→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 36→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 37→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 38→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 39→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 40→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 41→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 42→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 43→
 44→const AppAuthModal = () => {
 45→  const {showAuthModal, closeAuthModal} = useAuth();
 46→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 47→}
 48→
 49→const AppSplash = () => {
 50→  const { loading } = useAuth();
 51→  return <Loader isLoading={loading} />;
 52→}
 53→
 54→const App = () => {
 55→
 56→  const theme = {
 57→    paragraph: 'editor-paragraph',
 58→    heading: {
 59→      h1: 'editor-heading-h1',
 60→      h2: 'editor-heading-h2',
 61→      h3: 'editor-heading-h3',
 62→    },
 63→    quote: 'editor-quote',
 64→    text: {
 65→      bold: 'editor-text-bold',
 66→      italic: 'editor-text-italic',
 67→      underline: 'editor-text-underline',
 68→    }
 69→  }
 70→  
 71→  const initaConfig = {
 72→  namespace: "MyLexicalEditor",
 73→  theme,
 74→  //register nodes
 75→  nodes: [ImageNode, HeadingNode, QuoteNode],
 76→  onError(error){
 77→  throw error;
 78→  },
 79→}
 80→
 81→  return (
 82→    <>
 83→    <LexicalComposer initialConfig={initaConfig}>
 84→      <BrowserRouter>
 85→        <SeoManager />
 86→        <AppSplash />
 87→        <Suspense fallback={null}>
 88→          <AppAuthModal/>
 89→          <Routes>
 90→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 91→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 92→            <Route path='/profile' element={<MyProfile/>}>
 93→              <Route index element={<ProfilePostCards/>} />
 94→              <Route path='media' element={<ProfileMediaSection/>} />
 95→              <Route path='myOpinions' element={<MyOpinions/>}/>
 96→              <Route path='stories' element={<ProfileStoriesSection/>}/>
 97→            </Route>
 98→
 99→            <Route path='/visitProfile' element={<Visitprofile/>}>
100→              <Route index element={<VisitedProfilePostCards/>}/>
101→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
102→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
103→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
104→            </Route>
105→
106→            <Route path='/u/:username' element={<Visitprofile/>}>
107→              <Route index element={<VisitedProfilePostCards/>}/>
108→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
109→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
110→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
111→            </Route>
112→
113→            <Route path='/home' element={<HomePage/>}>
114→              <Route index element={<PostCards/>}/>
115→              <Route path='following' element={<PostCards/>}/>
116→              <Route path='explore' element={<ExplorePage/>}/>
117→              <Route path='contentViewer' element={<ContentView/>}/>
118→              <Route path='post/:journalId' element={<ContentView/>}/>
119→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
120→              <Route path='bookmark' element={<Bookmarks/>}/>
121→              <Route path='opinions'element={<OpinionsPage/>}/>
122→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
123→
124→              <Route path='settings' element={<SettingsPage/>}/>
125→
126→              {/* Stories routes */}
127→              <Route path='stories' element={<StoryBrowser/>}/>
128→              <Route path='stories/library' element={<StoryLibrary/>}/>
